section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/lint-shellcheck-hadolint-iac-floor.json",
  "type": "object",
  "required": [
    "linters_present",
    "rc_files_committed",
    "pre_commit_present",
    "ci_present",
    "ci_fails_on_violation"
  ],
  "properties": {
    "linters_present": {
      "type": "array",
      "minItems": 1,
      "uniqueItems": true,
      "items": {
        "enum": [
          "shellcheck",
          "hadolint",
          "yamllint",
          "actionlint",
          "tflint"
        ]
      }
    },
    "rc_files_committed": {
      "const": true
    },
    "pre_commit_present": {
      "const": true
    },
    "ci_present": {
      "const": true
    },
    "ci_fails_on_violation": {
      "const": true
    },
    "exclusions_justified": {
      "const": true
    }
  }
}
